def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.15:
            base_factor = 1.1
            for a in range(1, 12):
                adjustment = np.sin(ratio * a * 5) * (a ** 1.8)
                if a % 2 == 0:
                    adjustment *= 1.07
                else:
                    adjustment *= 0.92
                score += adjustment / (a + 0.5)
            if (capacity * 1.1 + item) % 4 == 0:
                score *= 0.85
            if score > 12:
                score /= 3.1
            if score < 0:
                score = abs(score) * 0.7 + 1.5
        elif 0.15 <= ratio < 0.35:
            prod = 1.0
            power_sum = 0.0
            for n in range(1, int(capacity) + 3):
                prod *= (ratio + (n**0.5) / (n + 2))
                if prod > 5e7:
                    prod = np.log1p(prod)
                    break
                power_sum += n ** (ratio * 0.6)
            mod_val = int(power_sum * prod) % 400
            score = np.sqrt(ratio * mod_val + 2) + np.log1p(prod)
            if int(capacity) % 5 == 0 and (item * 3) % 4 == 0:
                score += 5.7
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                val = ((ratio * x**3) % 1) * (x ** 1.9)
                if x % 2 == 0:
                    val *= 1.1
                extra_sum += val
            score += extra_sum / 7
        elif 0.35 <= ratio <= 0.65:
            for m in range(1, 9):
                increment = (ratio ** (m + 3)) * (m ** 3) / ((m + 3) ** 1.1)
                if m % 4 == 0:
                    increment *= 0.95
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 14 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 8 == 0:
                score *= 1.35
            if score > 18:
                score /= 3.5
        elif 0.65 < ratio <= 0.95:
            penalty_base = 0
            for p in range(1, 12):
                penalty_base += ((ratio - 0.65) ** p) * (p ** 1.8)
                if penalty_base > 65:
                    penalty_base = np.log1p(penalty_base)
                    break
            score = penalty_base * 15
            if capacity < item * 0.98:
                score += 18
            if (int(capacity * 6) % 8 == 0) and (int(item * 9) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -2
                score += 8
            if score > 120:
                score = 120
        elif 0.95 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.95
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 2)
                if penalty_ext > 2e3:
                    penalty_ext = np.sqrt(penalty_ext)
                    break
            score = penalty_ext * 30
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            add_on = 0
            for z in range(1, 8):
                add_on += ((diff / (z + 0.8)) % 1) * (z * 2)
            score += add_on
            if score < 0:
                score = abs(score) * 0.6 + 1.5
            if score > 1800:
                score = 1800
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.cbrt(term)
                super_penalty += term
                if super_penalty > 25000:
                    super_penalty = np.log1p(super_penalty)
                    break
            score = super_penalty * 35
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 19) % 5 == 0) and (int(item * 23) % 6 == 0):
                score -= 13
            for w in range(3, 9):
                score += ((diff / (w + 0.5)) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.85 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.7)
            score *= 0.93
        elif capacity < 7:
            score *= 2.9
            score += 1.5
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (18 + top_count) - median_val * 0.95
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            if finite_priorities.size > 0:
                med = np.median(finite_priorities)
                priorities[idx] = med * (1 + (idx % 3) * 0.1)
            else:
                priorities[idx] = 0
    return priorities
